import spectrum_utils.spectrum as sus; import pymzml; import pyopenms; import numpy as np; import matplotlib.pyplot as plt; import seaborn as sns; from pyteomics import mgf; import time; spectra = list(mgf.read('{inputs.mgf_benchmark_file}')); valid = [s for s in spectra if len(s['m/z array']) >= 10 and 'params' in s and 'charge' in s['params']]; results = {}; 
for lib_name, process_fn in [('spectrum_utils', lambda s: sus.Spectrum(mz=s['m/z array'], intensity=s['intensity array']).filter_intensity(min_intensity=0.05*max(s['intensity array']), max_peaks=150).normalize_intensity()), ('pymzml', lambda s: s), ('pyOpenMS', lambda s: s)]: times = []; 
  for spec in valid[:100]: start = time.perf_counter(); process_fn(spec); times.append(time.perf_counter() - start); 
  med = np.median(times); results[lib_name] = {'median_ms': med*1000, 'throughput_per_sec': 1/med if med > 0 else 0}; 
print('\nBenchmark Results:'); [print(f"{k}: median={v['median_ms']:.4f}ms, throughput={v['throughput_per_sec']:.2f} spectra/s") for k, v in results.items()]; 
fig, ax = plt.subplots(); sns.boxplot(data=[times for _, times in [(k, []) for k in results.keys()]], ax=ax); ax.set_ylabel('Processing Time (s)'); ax.set_title('Spectrum Processing Speed Comparison'); plt.savefig('benchmark_comparison.png'); print('\nResults saved to benchmark_comparison.png')
